import React from 'react';
import './skills.css';
import './new.css';
import { motion } from 'framer-motion';
import SemiDonutChart from './SemiDonutChart';

const skillsData = {
  languages: [
    { txt: "HTML", percentage: 70 },
    { txt: "CSS", percentage: 45 },
    { txt: "JavaScript", percentage: 50 },
    { txt: "React JS", percentage: 70 },
    { txt: "C", percentage: 70 },
    { txt: "C++", percentage: 60 },
    { txt: "Python", percentage: 65 },
  ],
  libraries: [
    { txt: "NumPy", percentage: 60 },
    { txt: "Pandas", percentage: 50 },
    { txt: "Python", percentage: 70 },
  ]
};

const Skills = () => {
  return (
    <motion.div
      initial={{ opacity: 0, y: 40 }}
      whileInView={{ opacity: 1, y: 0 }}
      transition={{ delay: 0.2, duration: 0.5 }}
      viewport={{ margin: "-100px", once: true }}
      className='skills-container'
    >
      <h2 className='heading1'>Projects</h2>

      <section className="skills-section">
        <h3 className='heading2'>Languages</h3>
        <div className="skills-grid">
          {skillsData.languages.map((skill, idx) => (
            <SemiDonutChart key={idx} {...skill} fill="#03B0FD" />
          ))}
        </div>
      </section>

      <motion.section
        initial={{ opacity: 0, y: 40 }}
        whileInView={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.2, duration: 0.5 }}
        viewport={{ margin: "-100px", once: true }}
        className="skills-section"
      >
        <h3 className='heading2'>Libraries</h3>
        <div className="skills-grid">
          {skillsData.libraries.map((skill, idx) => (
            <SemiDonutChart key={idx} {...skill} fill="#03B0FD" />
          ))}
        </div>
      </motion.section>
    </motion.div>
  );
};

export default Skills;
